// Extract and validate the issue array from the AI agent output
const item = $input.first();
const raw = item.json.output || item.json.text || item.json.message || '';

let issues = [];

try {
  // Strip markdown code fences if AI wrapped the JSON
  const cleaned = raw
    .replace(/```json?\s*/g, '')
    .replace(/```\s*/g, '')
    .trim();

  const parsed = JSON.parse(cleaned);

  if (Array.isArray(parsed)) {
    issues = parsed;
  } else if (parsed.issues && Array.isArray(parsed.issues)) {
    issues = parsed.issues;
  } else {
    throw new Error('Unexpected JSON structure — expected an array');
  }
} catch (e) {
  throw new Error(`Failed to parse AI output into issues: ${e.message}\n\nRaw output: ${raw.substring(0, 500)}`);
}

// Validate and normalise each issue
const validated = issues.map((issue, i) => {
  if (!issue.title || typeof issue.title !== 'string') {
    throw new Error(`Issue at index ${i} is missing a valid title`);
  }
  return {
    title: issue.title.trim(),
    body: issue.body || '',
    labels: Array.isArray(issue.labels) ? issue.labels : [],
    assignee: issue.assignee || null
  };
});

// Return one item per issue so the loop processes them individually
return validated.map(issue => ({ json: issue }));

// After all issues are created, produce a summary
// This node runs after the loop completes (connected to loop's 'done' output)
const items = $input.all();

const created = items.map(item => ({
  number: item.json.number,
  title: item.json.title,
  url: item.json.html_url,
  state: item.json.state
}));

console.log(`Created ${created.length} GitHub issues.`);

return [{ json: { createdIssues: created, count: created.length } }];
